+//! Response types and the [`IntoResponse`] trait.
+//!
+//! Handlers return types that implement [`IntoResponse`], which converts them
+//! into an HTTP response. Common types like `String`, `&str`, `Json<T>`, and
+//! tuples are supported out of the box.
+
+use std::collections::HashMap;
+use std::fmt;
+
+use crate::bytes::Bytes;
+
+// ─── Status Codes ────────────────────────────────────────────────────────────
+
+/// HTTP status code.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
+pub struct StatusCode(u16);
+
+impl StatusCode {
+    // 1xx Informational
+    /// 100 Continue
+    pub const CONTINUE: Self = Self(100);
+
+    // 2xx Success
+    /// 200 OK
+    pub const OK: Self = Self(200);
+    /// 201 Created
+    pub const CREATED: Self = Self(201);
+    /// 202 Accepted
+    pub const ACCEPTED: Self = Self(202);
+    /// 204 No Content
+    pub const NO_CONTENT: Self = Self(204);
+
+    // 3xx Redirection
+    /// 301 Moved Permanently
+    pub const MOVED_PERMANENTLY: Self = Self(301);
+    /// 302 Found
+    pub const FOUND: Self = Self(302);
+    /// 303 See Other
+    pub const SEE_OTHER: Self = Self(303);
+    /// 304 Not Modified
+    pub const NOT_MODIFIED: Self = Self(304);
+    /// 307 Temporary Redirect
+    pub const TEMPORARY_REDIRECT: Self = Self(307);
+    /// 308 Permanent Redirect
+    pub const PERMANENT_REDIRECT: Self = Self(308);
+
+    // 4xx Client Error
+    /// 400 Bad Request
+    pub const BAD_REQUEST: Self = Self(400);
+    /// 401 Unauthorized
+    pub const UNAUTHORIZED: Self = Self(401);
+    /// 403 Forbidden
+    pub const FORBIDDEN: Self = Self(403);
+    /// 404 Not Found
+    pub const NOT_FOUND: Self = Self(404);
+    /// 405 Method Not Allowed
+    pub const METHOD_NOT_ALLOWED: Self = Self(405);
+    /// 409 Conflict
+    pub const CONFLICT: Self = Self(409);
+    /// 413 Payload Too Large
+    pub const PAYLOAD_TOO_LARGE: Self = Self(413);
+    /// 415 Unsupported Media Type
+    pub const UNSUPPORTED_MEDIA_TYPE: Self = Self(415);
+    /// 422 Unprocessable Entity
+    pub const UNPROCESSABLE_ENTITY: Self = Self(422);
+    /// 429 Too Many Requests
+    pub const TOO_MANY_REQUESTS: Self = Self(429);
+
+    // 5xx Server Error
+    /// 500 Internal Server Error
+    pub const INTERNAL_SERVER_ERROR: Self = Self(500);
+    /// 501 Not Implemented
+    pub const NOT_IMPLEMENTED: Self = Self(501);
+    /// 502 Bad Gateway
+    pub const BAD_GATEWAY: Self = Self(502);
+    /// 503 Service Unavailable
+    pub const SERVICE_UNAVAILABLE: Self = Self(503);
+    /// 504 Gateway Timeout
+    pub const GATEWAY_TIMEOUT: Self = Self(504);
+
+    /// Create a status code from a raw value.
+    #[must_use]
+    pub const fn from_u16(code: u16) -> Self {
+        Self(code)
+    }
+
+    /// Return the numeric status code.
+    #[must_use]
+    pub const fn as_u16(self) -> u16 {
+        self.0
+    }
+
+    /// Returns `true` if the status code indicates success (2xx).
+    #[must_use]
+    pub const fn is_success(self) -> bool {
+        self.0 >= 200 && self.0 < 300
+    }
+
+    /// Returns `true` if the status code indicates a client error (4xx).
+    #[must_use]
+    pub const fn is_client_error(self) -> bool {
+        self.0 >= 400 && self.0 < 500
+    }
+
+    /// Returns `true` if the status code indicates a server error (5xx).
+    #[must_use]
+    pub const fn is_server_error(self) -> bool {
+        self.0 >= 500 && self.0 < 600
+    }
+}
+
+impl fmt::Display for StatusCode {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        write!(f, "{}", self.0)
+    }
